import React, { useEffect, useMemo, useState } from "react";

const OUTDOOR_KEYWORDS = ["football", "soccer", "park", "outdoor", "cycling", "hiking", "training"];

function Preview({ draftActivity, onConfirm, onBack }) {
  const [name, setName] = useState(draftActivity.name || "");
  const [dateTime, setDateTime] = useState(draftActivity.dateTime || "");
  const [weather, setWeather] = useState(null);
  const [loadingWeather, setLoadingWeather] = useState(true);
  const [weatherError, setWeatherError] = useState("");

  useEffect(() => {
    const fetchWeather = async () => {
      try {
        setLoadingWeather(true);
        setWeatherError("");
        const apiKey = process.env.REACT_APP_WEATHER_API_KEY;
        if (!apiKey) {
          throw new Error("Missing REACT_APP_WEATHER_API_KEY in .env file.");
        }

        const response = await fetch(
          `https://api.openweathermap.org/data/2.5/weather?q=Bergen,NO&appid=${apiKey}&units=metric`
        );

        if (!response.ok) {
          throw new Error("Could not fetch weather from OpenWeather.");
        }

        const data = await response.json();
        setWeather({
          temperature: data.main.temp,
          condition: data.weather?.[0]?.main || "Unknown",
          description: data.weather?.[0]?.description || "No details"
        });
      } catch (error) {
        setWeatherError(error.message);
      } finally {
        setLoadingWeather(false);
      }
    };

    fetchWeather();
  }, []);

  const checklist = useMemo(() => {
    const list = [];
    const lowerName = name.toLowerCase();
    const isOutdoor = OUTDOOR_KEYWORDS.some((keyword) => lowerName.includes(keyword));

    // Activity-specific baseline checklist.
    if (lowerName.includes("football")) {
      list.push("Shoes", "Water Bottle");
    } else {
      list.push("Comfortable Clothes", "Water Bottle");
    }

    const weatherCondition = weather?.condition?.toLowerCase() || "";
    const isRainy = weatherCondition.includes("rain") || weatherCondition.includes("drizzle");
    const isCold = typeof weather?.temperature === "number" && weather.temperature < 10;

    // General weather rules from requirements.
    if (isRainy) {
      list.push("Raincoat");
    }
    if (isCold) {
      list.push("Jacket", "Gloves");
    }

    // Outdoor extras.
    if (isOutdoor) {
      if (isRainy) list.push("Umbrella");
      if (isCold) list.push("Hat");
    }

    return Array.from(new Set(list));
  }, [name, weather]);

  const handleConfirm = () => {
    if (!name || !dateTime) {
      alert("Please provide both activity name and date/time.");
      return;
    }

    const saved = {
      id: Date.now(),
      name,
      dateTime,
      checklist,
      screenshotPreviewUrl: draftActivity.screenshotPreviewUrl || "",
      weatherSummary: weather
        ? `${weather.condition}, ${Math.round(weather.temperature)}°C`
        : weatherError || "Weather unavailable"
    };

    onConfirm(saved);
    // Simulated reminder message.
    alert("Reminder set: Activity confirmed and added to your calendar.");
  };

  const buttonStyle = {
    border: "none",
    padding: "0.7rem 1.1rem",
    borderRadius: 8,
    fontWeight: 600,
    cursor: "pointer",
    marginRight: "0.75rem"
  };

  return (
    <div>
      <h2 style={{ marginTop: 0 }}>Preview Screen</h2>
      <p style={{ color: "#475569", marginTop: 0 }}>
        Confirm activity details and generated checklist before saving.
      </p>

      {draftActivity.screenshotPreviewUrl && (
        <div style={{ marginBottom: "1rem" }}>
          <img
            src={draftActivity.screenshotPreviewUrl}
            alt="Activity screenshot preview"
            style={{ width: "100%", maxWidth: 360, borderRadius: 10, border: "1px solid #cbd5e1" }}
          />
          <p style={{ margin: "0.5rem 0 0", color: "#475569" }}>
            Extracted from screenshot (simulated): {draftActivity.screenshotName}
          </p>
        </div>
      )}

      <label style={{ display: "block", fontWeight: 600, marginBottom: "0.35rem" }}>Activity Name</label>
      <input
        value={name}
        onChange={(e) => setName(e.target.value)}
        style={{
          width: "100%",
          padding: "0.65rem",
          borderRadius: 8,
          border: "1px solid #cbd5e1",
          marginBottom: "0.9rem"
        }}
      />

      <label style={{ display: "block", fontWeight: 600, marginBottom: "0.35rem" }}>Date and Time</label>
      <input
        type="datetime-local"
        value={dateTime}
        onChange={(e) => setDateTime(e.target.value)}
        style={{
          width: "100%",
          padding: "0.65rem",
          borderRadius: 8,
          border: "1px solid #cbd5e1",
          marginBottom: "0.9rem"
        }}
      />

      <div
        style={{
          border: "1px solid #e2e8f0",
          borderRadius: 12,
          padding: "1rem",
          background: "#f8fafc",
          marginBottom: "1rem"
        }}
      >
        <h3 style={{ marginTop: 0 }}>Weather in Bergen, Norway</h3>
        {loadingWeather && <p>Loading weather...</p>}
        {!loadingWeather && weather && (
          <p>
            {weather.condition} ({weather.description}), {Math.round(weather.temperature)}°C
          </p>
        )}
        {!loadingWeather && weatherError && <p style={{ color: "#b91c1c" }}>{weatherError}</p>}
      </div>

      <div style={{ border: "1px solid #e2e8f0", borderRadius: 12, padding: "1rem", marginBottom: "1rem" }}>
        <h3 style={{ marginTop: 0 }}>Generated Checklist</h3>
        <ul style={{ margin: 0, paddingLeft: "1.2rem" }}>
          {checklist.map((item) => (
            <li key={item}>{item}</li>
          ))}
        </ul>
      </div>

      <button onClick={handleConfirm} style={{ ...buttonStyle, background: "#2563eb", color: "#fff" }}>
        Confirm
      </button>
      <button onClick={onBack} style={{ ...buttonStyle, background: "#e2e8f0", color: "#0f172a" }}>
        Back
      </button>
    </div>
  );
}

export default Preview;
